mapper.select:
SELECT 
  FROM  TB_INDVDL_PGE_CNTNTS A
 WHERE  A.CNTNTS_ID = #{cntntsId}

mapper.insert:
INSERT  INTO TB_INDVDL_PGE_CNTNTS
      ( CNTNTS_ID
      , CNTNTS_NM
      , CNTC_URL
      , CNTNTS_USE_AT
      , CNTNTS_LINK_URL
      , CNTNTS_DC
      , FRST_REGIST_PNTTM
      , FRST_REGISTER_ID )
VALUES  ( #{cntntsId}
        , #{cntntsNm}
        , #{cntcUrl}
        , #{cntntsUseAt}
        , #{cntntsLinkUrl}
        , #{cntntsDc}
        , CURRENT_TIMESTAMP
        , #{frstRegisterId} )

mapper.update:
UPDATE  TB_INDVDL_PGE_CNTNTS
   SET  CNTNTS_NM       = #{cntntsNm}
      , CNTC_URL        = #{cntcUrl}
      , CNTNTS_USE_AT   = #{cntntsUseAt}
      , CNTNTS_LINK_URL = #{cntntsLinkUrl}
      , CNTNTS_DC       = #{cntntsDc}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  CNTNTS_ID = #{cntntsId}
